READ_OPERATION(T, Q)
BEGIN
 // T: transaction, Q: data item
 // TS(T): timestamp of transaction T
 // WTS(Q): write timestamp of data item Q

 IF TS(T) >= WTS(Q) THEN
 // Read is allowed
 READ(Q)
 // Update RTS(Q) if needed
 IF TS(T) > RTS(Q) THEN
 RTS(Q) = TS(T)
 ENDIF
 RETURN SUCCESS
 ELSE
 // Read is rejected - rollback transaction
 ROLLBACK(T)
 RETURN REJECTED
 ENDIF
END

WRITE_OPERATION(T, Q)
BEGIN
 // T: transaction, Q: data item
 // TS(T): timestamp of transaction T
 // RTS(Q): read timestamp of data item Q
 // WTS(Q): write timestamp of data item Q

 // Both conditions must be satisfied
 IF (TS(T) >= RTS(Q)) AND (TS(T) >= WTS(Q)) THEN
 // Write is allowed
 WRITE(Q)
 // Update WTS(Q)
 WTS(Q) = TS(T)
 RETURN SUCCESS
 ELSE
 // Write is rejected - rollback transaction
 ROLLBACK(T)
 RETURN REJECTED
 ENDIF
END

THOMAS_WRITE_OPERATION(T, Q)
BEGIN
 // Check first condition: newer than last writer?
 IF TS(T) < WTS(Q) THEN
 // Someone newer has written - ignore this outdated write
 // This is the Thomas' exception
 IGNORE_WRITE()
 RETURN IGNORED
 ENDIF

 // Check second condition: newer than last reader?
 IF TS(T) < RTS(Q) THEN
 // Someone newer has read - cannot write
 ROLLBACK(T)
 RETURN REJECTED
 ENDIF

 // Both conditions pass - allow write
 WRITE(Q)
 WTS(Q) = TS(T)
 RETURN SUCCESS
END

RESTART_TRANSACTION(T)
BEGIN
 // Generate new timestamp for restarted transaction
 NEW_TIMESTAMP = GET_CURRENT_TIMESTAMP()

 // Assign new timestamp
 TS(T) = NEW_TIMESTAMP

 // Clear any partial results
 CLEAR_WRITE_SET(T)
 CLEAR_READ_SET(T)

 // Restart transaction from beginning
 RESTART_FROM_BEGINNING(T)

 RETURN T
END
